from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    from collections import defaultdict

    # Group triples by subject to handle different entities properly
    triples_by_subject = defaultdict(list)
    for triple in triples:
        triples_by_subject[triple.subject].append(triple)

    # Use the first subject as the primary (monument) subject
    primary_subject = triples[0].subject
    other_subjects = [s for s in triples_by_subject.keys() if s != primary_subject]

    # Build clauses for the primary subject (monument)
    monument_clauses: list[str] = []
    for triple in triples_by_subject[primary_subject]:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        if p == "category":
            monument_clauses.append(f"is a {o}")
        elif p == "country":
            monument_clauses.append(f"is located in {o}")
        elif p == "location":
            monument_clauses.append(f"is located in {o}")
        elif p == "municipality":
            monument_clauses.append(f"is in the municipality of {o}")
        elif p == "state":
            monument_clauses.append(f"in the state of {o}")
        elif p == "district":
            monument_clauses.append(f"is part of the district {o}")
        elif p in ("established", "foundingDate"):
            monument_clauses.append(f"was established on {o}")
        elif p in ("owner", "owningOrganisation"):
            monument_clauses.append(f"is owned by {o}")
        elif p == "inaugurationDate":
            monument_clauses.append(f"was inaugurated on {o}")
        elif p == "dedicatedTo":
            monument_clauses.append(f"is dedicated to {o}")
        elif p == "designer":
            monument_clauses.append(f"was designed by {o}")
        elif p == "material":
            monument_clauses.append(f"is made of {o}")
        elif p == "nativeName":
            monument_clauses.append(f'has native name "{o}"')
        elif p == "nearestCity":
            monument_clauses.append(f"is near {o}")
        elif p == "district":
            monument_clauses.append(f"is in the district of {o}")
        else:
            monument_clauses.append(f"{p.replace(' ', ' ')} {o}")

    # Build clauses for related entities (country, state, etc.)
    entity_clauses: list[str] = []
    for subject in other_subjects:
        for triple in triples_by_subject[subject]:
            p = triple.predicate
            o = triple.object.strip('"')

            if p == "capital":
                entity_clauses.append(f"{subject}, where the capital is {o}")
            elif p == "largestCity":
                entity_clauses.append(f"{subject}, whose largest city is {o}")
            elif p == "country":
                entity_clauses.append(f"{subject}, which is in {o}")
            elif p == "currency":
                entity_clauses.append(f"{subject}, which uses {o}")
            elif p == "leader":
                entity_clauses.append(f"{subject}, led by {o}")
            elif p == "leaderTitle":
                entity_clauses.append(f"{subject}, where the leader's title is {o}")
            elif p == "language":
                entity_clauses.append(f"{subject}, where {o} is spoken")
            elif p == "religion":
                entity_clauses.append(f"{subject}, where the religion is {o}")
            elif p == "ethnicGroup":
                entity_clauses.append(f"{subject}, with ethnic group {o}")
            elif p == "legislature":
                entity_clauses.append(f"{subject}, with legislature {o}")
            elif "hasToIts" in p:
                # Handle directional relationships
                direction = p.replace("hasToIts", "").lower()
                entity_clauses.append(f"{subject}, which has {direction} {o}")
            else:
                entity_clauses.append(f"{subject}, with {p.replace(' ', ' ')} {o}")

    # Combine monument and entity clauses into a coherent sentence
    all_clauses = monument_clauses + entity_clauses

    # Build the final sentence with proper flow
    if len(all_clauses) == 1:
        sentence = f"{primary_subject} {all_clauses[0]}."
    else:
        # Join first clause with subject, then add remaining clauses with commas
        sentence = f"{primary_subject} {all_clauses[0]}"
        for clause in all_clauses[1:]:
            sentence += f", {clause}"
        sentence += "."

    return sentence

# EVOLVE-BLOCK-END
